class User:
    def __init__(self, name):
        self.name = name

    def greet(self):
        return f"hi, {self.name}"

u = User("maya")
print(u.greet())

class Order:
    def __init__(self, total):
        self.total = total

    def with_tax(self):
        return self.total * 1.08

o = Order(100)
print(o.total)         # attribute — no parens
print(o.with_tax())    # method — needs parens

class Pet:
    def __init__(self, name, kind):
        self.name = name
        self.kind = kind

    def describe(self):
        return f"{self.name} is a {self.kind}"

rex = Pet("rex", "dog")
whiskers = Pet("whiskers", "cat")
print(rex.describe())
print(whiskers.describe())

class Profile:
    def __init__(self, name):
        self.name = name

    def display(self):
        return f"profile: {___.name}"

print(Profile("maya").display())

